SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation") AS QualifyingEncounter WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND fhirpath_text(QualifyingEncounter.resource, 'status') = 'finished' AND EXISTS (SELECT 1 FROM (SELECT patient_id, resource FROM "Condition: Heart Failure (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Heart Failure (qicore-condition-encounter-diagnosis)") AS HeartFailure WHERE intervalOverlaps(CASE WHEN fhirpath_text(HeartFailure.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), fhirpath_text(HeartFailure.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HeartFailure.resource, 'onsetDateTime'), fhirpath_text(HeartFailure.resource, 'onsetPeriod.start'), fhirpath_text(HeartFailure.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(QualifyingEncounter.resource, 'period')) AND (fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HeartFailure.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HeartFailure.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND HeartFailure.patient_id = QualifyingEncounter.patient_id)
),
"AHA.Moderate or Severe LVSD Findings" AS (
(SELECT patient_id, resource FROM "Observation: Ejection Fraction" AS EjectionFraction WHERE quantity_compare(parse_quantity(EjectionFraction.value), parse_quantity('{"value": 40.0, "unit": "%", "system": "http://unitsofmeasure.org"}'), '<=') AND array_contains(['final', 'amended', 'corrected'], EjectionFraction.status)) UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Moderate or Severe LVSD (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Moderate or Severe LVSD (qicore-condition-encounter-diagnosis)" UNION (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Left ventricular systolic dysfunction (disorder) (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Left ventricular systolic dysfunction (disorder) (qicore-condition-encounter-diagnosis)") AS LVSDDiagnosis WHERE in_valueset(LVSDDiagnosis.resource, 'severity', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1092'))) AS ModerateOrSevereLVSD WHERE (fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(ModerateOrSevereLVSD.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(ModerateOrSevereLVSD.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()'))
),
"AHA.Qualifying Outpatient Encounter During Measurement Period" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit" UNION SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Patient Provider Interaction") AS ValidEncounter WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ValidEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ValidEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND fhirpath_text(ValidEncounter.resource, 'status') = 'finished'
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD" AS (
SELECT * FROM "AHA.Heart Failure Outpatient Encounter" AS HFOutpatientEncounter WHERE EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Moderate or Severe LVSD Findings") AS LVSDFindings WHERE intervalStart(COALESCE(CASE WHEN fhirpath_text(LVSDFindings.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), fhirpath_text(LVSDFindings.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LVSDFindings.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LVSDFindings.resource, 'onsetDateTime'), fhirpath_text(LVSDFindings.resource, 'onsetPeriod.start'), fhirpath_text(LVSDFindings.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, CASE WHEN fhirpath_text(LVSDFindings.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LVSDFindings.resource, 'effective')), '{') THEN fhirpath_text(LVSDFindings.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(LVSDFindings.resource, 'effective'), fhirpath_text(LVSDFindings.resource, 'effective'), TRUE, TRUE) END)) < intervalEnd(fhirpath_text(HFOutpatientEncounter.resource, 'period')) AND LVSDFindings.patient_id = HFOutpatientEncounter.patient_id)
),
"AHA.Is Adults With Two Qualifying Outpatient Encounters and One Heart Failure Outpatient Encounter During the Measurement Period" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) - EXTRACT(YEAR FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) - CASE WHEN EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) OR EXTRACT(MONTH FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) = EXTRACT(MONTH FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) AND EXTRACT(DAY FROM TRY_CAST(CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP)) < EXTRACT(DAY FROM TRY_CAST((SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1) AS TIMESTAMP)) THEN 1 ELSE 0 END >= 18 AND EXISTS (SELECT * FROM "AHA.Qualifying Outpatient Encounter During Measurement Period" AS Encounter1 WHERE Encounter1.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Qualifying Outpatient Encounter During Measurement Period") AS Encounter2 WHERE NOT CASE WHEN fhirpath_text(Encounter2.resource, 'id') IS NULL AND fhirpath_text(Encounter1.resource, 'id') IS NULL THEN TRUE WHEN fhirpath_text(Encounter2.resource, 'id') IS NULL OR fhirpath_text(Encounter1.resource, 'id') IS NULL THEN FALSE ELSE fhirpath_text(Encounter2.resource, 'id') = fhirpath_text(Encounter1.resource, 'id') END AND Encounter2.patient_id = Encounter1.patient_id)) AND EXISTS (SELECT 1 FROM "AHA.Heart Failure Outpatient Encounter" AS sub WHERE sub.patient_id = p.patient_id)
),
"AHA.Has Heart Transplant" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Heart Transplant" AS HeartTransplant WHERE HeartTransplant.patient_id = p.patient_id AND fhirpath_text(HeartTransplant.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE intervalStart(CASE WHEN fhirpath_text(HeartTransplant.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartTransplant.resource, 'performed')), '{') THEN fhirpath_text(HeartTransplant.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HeartTransplant.resource, 'performed'), fhirpath_text(HeartTransplant.resource, 'performed'), TRUE, TRUE) END) < intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartTransplant.patient_id))
),
"AHA.Has Heart Transplant Complications" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Heart Transplant Complications (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Heart Transplant Complications (qicore-condition-problems-health-concerns)") AS HeartTransplantComplications WHERE HeartTransplantComplications.patient_id = p.patient_id AND (fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(HeartTransplantComplications.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE cqlBefore(CAST(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'recordedDate'), intervalStart(CASE WHEN fhirpath_text(HeartTransplantComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), fhirpath_text(HeartTransplantComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HeartTransplantComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HeartTransplantComplications.resource, 'onsetDateTime'), fhirpath_text(HeartTransplantComplications.resource, 'onsetPeriod.start'), fhirpath_text(HeartTransplantComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AS VARCHAR), CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR)) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = HeartTransplantComplications.patient_id))
),
"AHA.Has Left Ventricular Assist Device" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Left Ventricular Assist Device Placement" AS LVADOutpatient WHERE LVADOutpatient.patient_id = p.patient_id AND fhirpath_text(LVADOutpatient.resource, 'status') = 'completed' AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE intervalStart(CASE WHEN fhirpath_text(LVADOutpatient.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(LVADOutpatient.resource, 'performed')), '{') THEN fhirpath_text(LVADOutpatient.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(LVADOutpatient.resource, 'performed'), fhirpath_text(LVADOutpatient.resource, 'performed'), TRUE, TRUE) END) < intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = LVADOutpatient.patient_id))
),
"AHA.Has Left Ventricular Assist Device Complications" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Left Ventricular Assist Device Complications (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Left Ventricular Assist Device Complications (qicore-condition-problems-health-concerns)") AS LVADComplications WHERE LVADComplications.patient_id = p.patient_id AND (fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(LVADComplications.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND EXISTS (SELECT 1 FROM (SELECT * FROM "AHA.Heart Failure Outpatient Encounter with History of Moderate or Severe LVSD") AS ModerateOrSevereLVSDHFOutpatientEncounter WHERE cqlBefore(CAST(COALESCE(fhirpath_text(LVADComplications.resource, 'recordedDate'), intervalStart(CASE WHEN fhirpath_text(LVADComplications.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), fhirpath_text(LVADComplications.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(LVADComplications.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(LVADComplications.resource, 'onsetDateTime'), fhirpath_text(LVADComplications.resource, 'onsetPeriod.start'), fhirpath_text(LVADComplications.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END)) AS VARCHAR), CAST(intervalEnd(fhirpath_text(ModerateOrSevereLVSDHFOutpatientEncounter.resource, 'period')) AS VARCHAR)) AND ModerateOrSevereLVSDHFOutpatientEncounter.patient_id = LVADComplications.patient_id))
),
"Outpatient Encounter During Measurement Period" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Outpatient Consultation" UNION SELECT patient_id, resource FROM "Encounter: Care Services in Long Term Residential Facility" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Nursing Facility Visit") AS QualifyingEncounter WHERE CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(QualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(QualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= CAST(LEFT(REPLACE(CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND fhirpath_text(QualifyingEncounter.resource, 'status') = 'finished'
),
"Coronary Artery Disease Encounter" AS (
SELECT * FROM "Outpatient Encounter During Measurement Period" AS ValidQualifyingEncounter WHERE EXISTS (SELECT 1 FROM "Condition: Coronary Artery Disease No MI (qicore-condition-problems-health-concerns)" AS CoronaryArteryDisease WHERE CASE WHEN (fhirpath_bool(CoronaryArteryDisease.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(CoronaryArteryDisease.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(CoronaryArteryDisease.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(CoronaryArteryDisease.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') THEN CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(CoronaryArteryDisease.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')), fhirpath_text(CoronaryArteryDisease.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(CoronaryArteryDisease.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(ValidQualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(CoronaryArteryDisease.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')), fhirpath_text(CoronaryArteryDisease.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(CoronaryArteryDisease.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(CoronaryArteryDisease.resource, 'onsetDateTime'), fhirpath_text(CoronaryArteryDisease.resource, 'onsetPeriod.start'), fhirpath_text(CoronaryArteryDisease.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(ValidQualifyingEncounter.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) ELSE NULL END AND CoronaryArteryDisease.patient_id = ValidQualifyingEncounter.patient_id)
),
"History of Cardiac Surgery Prior to Encounter" AS (
