ycardiaDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BradycardiaDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(BradycardiaDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BradycardiaDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BradycardiaDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaDiagnosis.resource, 'recordedDate')), fhirpath_text(BradycardiaDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BradycardiaDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BradycardiaDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BradycardiaDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BradycardiaDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BradycardiaDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BradycardiaDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BradycardiaDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BradycardiaDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) ELSE NULL END)
),
"Has Cardiac Pacer Device Implanted with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Procedure: Cardiac Pacer" AS ImplantedCardiacPacer WHERE ImplantedCardiacPacer.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying CAD Encounter and History of Moderate or Severe LVSD") AS CADEncounterModerateOrSevereLVSD WHERE intervalStart(CASE WHEN fhirpath_text(ImplantedCardiacPacer.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ImplantedCardiacPacer.resource, 'performed')), '{') THEN fhirpath_text(ImplantedCardiacPacer.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(ImplantedCardiacPacer.resource, 'performed'), fhirpath_text(ImplantedCardiacPacer.resource, 'performed'), TRUE, TRUE) END) < intervalEnd(fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period')) AND CADEncounterModerateOrSevereLVSD.patient_id = ImplantedCardiacPacer.patient_id))
),
"Has Consecutive Heart Rates Less than 50 with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "Observation (us-core-heart-rate)" AS HeartRateExam WHERE HeartRateExam.patient_id = p.patient_id AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying CAD Encounter and History of Moderate or Severe LVSD") AS CADEncounterModerateOrSevereLVSD WHERE intervalIncludes(fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period'), CASE WHEN fhirpath_text(HeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(HeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRateExam.resource, 'effective'), fhirpath_text(HeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(HeartRateExam.resource, 'value')), '{') THEN json_extract_string(fhirpath_text(HeartRateExam.resource, 'value'), '$.value') ELSE fhirpath_text(HeartRateExam.resource, 'value') END AS DOUBLE) < 50.0 AND TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text((SELECT resource FROM "Observation (us-core-heart-rate)" AS MostRecentPriorHeartRateExam WHERE intervalIncludes(fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period'), CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND intervalBefore(CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(HeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(HeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRateExam.resource, 'effective'), fhirpath_text(HeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND MostRecentPriorHeartRateExam.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(MostRecentPriorHeartRateExam.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value')), '{') THEN json_extract_string(fhirpath_text((SELECT resource FROM "Observation (us-core-heart-rate)" AS MostRecentPriorHeartRateExam WHERE intervalIncludes(fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period'), CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND intervalBefore(CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(HeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(HeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRateExam.resource, 'effective'), fhirpath_text(HeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND MostRecentPriorHeartRateExam.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(MostRecentPriorHeartRateExam.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value'), '$.value') ELSE fhirpath_text((SELECT resource FROM "Observation (us-core-heart-rate)" AS MostRecentPriorHeartRateExam WHERE intervalIncludes(fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period'), CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND intervalBefore(CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END, CASE WHEN fhirpath_text(HeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(HeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HeartRateExam.resource, 'effective'), fhirpath_text(HeartRateExam.resource, 'effective'), TRUE, TRUE) END) AND MostRecentPriorHeartRateExam.patient_id = p.patient_id ORDER BY intervalStart(CASE WHEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective')), '{') THEN fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), fhirpath_text(MostRecentPriorHeartRateExam.resource, 'effective'), TRUE, TRUE) END) DESC NULLS FIRST, json_extract_string(MostRecentPriorHeartRateExam.resource, '$.id') ASC NULLS LAST LIMIT 1), 'value') END AS DOUBLE) < 50.0 AND CADEncounterModerateOrSevereLVSD.patient_id = HeartRateExam.patient_id))
),
"Has Diagnosis of Allergy or Intolerance to Beta Blocker Therapy with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Allergy to Beta Blocker Therapy (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Intolerance to Beta Blocker Therapy (qicore-condition-problems-health-concerns)") AS BetaBlockerAllergyOrIntoleranceDiagnosis WHERE BetaBlockerAllergyOrIntoleranceDiagnosis.patient_id = p.patient_id AND CASE WHEN json_extract_string(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, '$.resourceType') = 'AllergyIntolerance' THEN intervalOverlaps(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset')), '{') THEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'lastOccurrence'), TRUE, TRUE), fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset')), '{') THEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'lastOccurrence'), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND (fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus') IS NULL OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''active'').exists()')) WHEN json_extract_string(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, '$.resourceType') = 'Condition' THEN (fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND intervalOverlaps(CASE WHEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND fhirpath_bool(BetaBlockerAllergyOrIntoleranceDiagnosis.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') ELSE FALSE END)
),
"Has Diagnosis of Cardiac Pacer in Situ with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Cardiac Pacer in Situ (qicore-condition-problems-health-concerns)" AS CardiacPacerDiagnosis WHERE CardiacPacerDiagnosis.patient_id = p.patient_id AND CASE WHEN fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()') THEN CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), fhirpath_text(CardiacPacerDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(CardiacPacerDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetDateTime'), fhirpath_text(CardiacPacerDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(CardiacPacerDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) ELSE NULL END)
),
"Has Atrioventricular Block with Qualifying CAD Encounter and History of Moderate or Severe LVSD without Cardiac Pacer" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Atrioventricular Block with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) AND NOT EXISTS (SELECT 1 FROM "Has Diagnosis of Cardiac Pacer in Situ with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) AND NOT EXISTS (SELECT 1 FROM "Has Cardiac Pacer Device Implanted with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id)
),
"Has Hypotension with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM "Condition: Hypotension (qicore-condition-problems-health-concerns)" AS HypotensionDiagnosis WHERE HypotensionDiagnosis.patient_id = p.patient_id AND CASE WHEN fhirpath_bool(HypotensionDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(HypotensionDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(HypotensionDiagnosis.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()') THEN CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(HypotensionDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')), fhirpath_text(HypotensionDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HypotensionDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(HypotensionDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')), fhirpath_text(HypotensionDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HypotensionDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HypotensionDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HypotensionDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HypotensionDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) ELSE NULL END)
),
"Has Medical or Patient Reason for Not Ordering Beta Blocker for LVSD" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "MedicationRequest: Beta Blocker Therapy for LVSD (medicationnotrequested)" AS NoBetaBlockerForLVSDOrdered WHERE NoBetaBlockerForLVSDOrdered.patient_id = p.patient_id AND array_contains(['active', 'completed'], fhirpath_text(NoBetaBlockerForLVSDOrdered.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(NoBetaBlockerForLVSDOrdered.resource, 'intent')) AND (in_valueset(NoBetaBlockerForLVSDOrdered.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1007') OR in_valueset(NoBetaBlockerForLVSDOrdered.resource, 'reasonCode', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1008')) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying CAD Encounter and History of Moderate or Severe LVSD") AS LVSDVisit WHERE CAST(LEFT(REPLACE(CAST(fhirpath_text(NoBetaBlockerForLVSDOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) >= CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(LVSDVisit.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(fhirpath_text(NoBetaBlockerForLVSDOrdered.resource, 'authoredOn') AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) <= COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(LVSDVisit.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND LVSDVisit.patient_id = NoBetaBlockerForLVSDOrdered.patient_id))
),
"Denominator Exceptions 1" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Arrhythmia with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Asthma with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Bradycardia with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Hypotension with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Consecutive Heart Rates Less than 50 with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Allergy or Intolerance to Beta Blocker Therapy Ingredient with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Diagnosis of Allergy or Intolerance to Beta Blocker Therapy with Qualifying CAD Encounter and History of Moderate or Severe LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Medical or Patient Reason for Not Ordering Beta Blocker for LVSD" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Has Atrioventricular Block with Qualifying CAD Encounter and History of Moderate or Severe LVSD without Cardiac Pacer" AS sub WHERE sub.patient_id = p.patient_id)
),
"Is Currently Taking Beta Blocker Therapy for LVSD" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM "MedicationRequest: Beta Blocker Therapy for LVSD" AS ActiveBetaBlockerForLVSD WHERE ActiveBetaBlockerForLVSD.patient_id = p.patient_id AND array_contains(['active', 'completed'], fhirpath_text(ActiveBetaBlockerForLVSD.resource, 'status')) AND array_contains(['order', 'original-order', 'reflex-order', 'filler-order', 'instance-order'], fhirpath_text(ActiveBetaBlockerForLVSD.resource, 'intent')) AND EXISTS (SELECT 1 FROM (SELECT * FROM "Qualifying CAD Encounter and History of Moderate or Severe LVSD") AS CADEncounterModerateOrSevereLVSD WHERE intervalOverlaps(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ActiveBetaBlockerForLVSD.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1), fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(list_extract(from_json(collapse_intervals(to_json(list_transform(from_json(fhirpath(ActiveBetaBlockerForLVSD.resource, 'dosageInstruction.timing.repeat.bounds'), '["VARCHAR"]'), _lt_DoseTime -> CASE WHEN _lt_DoseTime IS NULL THEN NULL WHEN starts_with(LTRIM(_lt_DoseTime), '{') THEN _lt_DoseTime ELSE intervalFromBounds(CAST(_lt_DoseTime AS VARCHAR), CAST(_lt_DoseTime AS VARCHAR), TRUE, TRUE) END))), '["VARCHAR"]'), 1)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(CADEncounterModerateOrSevereLVSD.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND CADEncounterModerateOrSevereLVSD.patient_id = ActiveBetaBlockerForLVSD.patient_id))
),
"Numerator 1" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "Has Beta Blocker Therapy for LVSD Ordered" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Is Currently Taking Beta Blocker Therapy for LVSD" AS sub WHERE sub.patient_id = p.patient_id)
),
"Qualifying CAD Encounter and Prior MI" AS (
SELECT * FROM "Qualifying CAD Encounter" AS EncounterWithCADProxy WHERE EXISTS (SELECT 1 FROM "Condition: Myocardial Infarction (qicore-condition-problems-health-concerns)" AS MyocardialInfarction WHERE LEFT(REPLACE(CAST(STRFTIME(CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(EncounterWithCADProxy.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS TIMESTAMP) - INTERVAL '3 year', '%Y-%m-%dT%H:%M:%S.%g') AS VARCHAR), ' ', 'T'), 10) <= CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(MyocardialInfarction.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')), fhirpath_text(MyocardialInfarction.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MyocardialInfarction.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AND CAST(LEFT(REPLACE(CAST(intervalStart(CASE WHEN fhirpath_text(MyocardialInfarction.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')), fhirpath_text(MyocardialInfarction.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(MyocardialInfarction.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(MyocardialInfarction.resource, 'onsetDateTime'), fhirpath_text(MyocardialInfarction.resource, 'onsetPeriod.start'), fhirpath_text(MyocardialInfarction.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) < LEFT(REPLACE(CAST(CAST(LEFT(REPLACE(CAST(intervalStart(fhirpath_text(EncounterWithCADProxy.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR) AS VARCHAR), ' ', 'T'), 10) AND NOT EXISTS (SELECT 1 FROM "AHA.Moderate or Severe LVSD Findings" AS sub WHERE sub.patient_id = EncounterWithCADProxy.patient_id) AND MyocardialInfarction.patient_id = EncounterWithCADProxy.patient_id)
),
"Has Allergy or Intolerance to Beta Blocker Therapy Ingredient with Qualifying CAD Encounter and Prior MI" AS (
SELECT p.patient_id FROM _patients AS p LEFT JOIN "Qualifying CAD Encounter and Prior MI" AS j1 ON j1.patient_id = p.patient_id WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "AllergyIntolerance: Beta Blocker Therapy Ingredient" UNION SELECT patient_id, resource FROM "AllergyIntolerance: Substance with beta adrenergic receptor antagonist mechanism of action (substance)") AS BetaBlockerAllergyIntolerance WHERE BetaBlockerAllergyIntolerance.patient_id = p.patient_id AND CASE WHEN json_extract_string(BetaBlockerAllergyIntolerance.resource, '$.resourceType') = 'AllergyIntolerance' THEN intervalOverlaps(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset')), '{') THEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'lastOccurrence'), TRUE, TRUE), fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(intervalFromBounds(CAST(intervalStart(CASE WHEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset')), '{') THEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset') ELSE intervalFromBounds(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onset'), TRUE, TRUE) END) AS VARCHAR), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'lastOccurrence'), TRUE, TRUE)) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND (fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus') IS NULL OR fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/allergyintolerance-clinical'' and code=''active'').exists()')) WHEN json_extract_string(BetaBlockerAllergyIntolerance.resource, '$.resourceType') = 'Condition' THEN (fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''active'').exists()') OR fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''recurrence'').exists()') OR fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-clinical'' and code=''relapse'').exists()')) AND fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') AND intervalOverlaps(CASE WHEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END, fhirpath_text(j1.resource, 'period')) AND COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(CASE WHEN fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetDateTime'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'onsetPeriod.start'), fhirpath_text(BetaBlockerAllergyIntolerance.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) > COALESCE(CAST(LEFT(REPLACE(CAST(intervalEnd(fhirpath_text(j1.resource, 'period')) AS VARCHAR), ' ', 'T'), 10) AS VARCHAR), LEFT(CAST('9999-12-31' AS VARCHAR), 10)) AND fhirpath_bool(BetaBlockerAllergyIntolerance.resource, 'verificationStatus.coding.where(system=''http://terminology.hl7.org/CodeSystem/condition-ver-status'' and code=''confirmed'').exists()') ELSE FALSE END)
),
"Has Arrhythmia with Qualifying CAD Encounter and Prior MI" AS (
